def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 5:
            priority += 6000 * np.exp(0.4 * usage_ratio)
            if capacity > 15:
                priority += 200 * np.log1p(capacity) + 80 * np.sin(capacity * 1.7)
            else:
                priority -= 60 * usage_ratio ** 1.2
            for p in range(1, 8):
                priority += ((-1)**p) * np.cos(usage_ratio * np.pi * p * 0.75) * 25 / p
            if usage_ratio > 6:
                priority += (usage_ratio - 6)**4 * 150
            elif 5.5 < usage_ratio <= 6:
                priority -= 90 * np.sin(usage_ratio * 3)
        elif 4 < usage_ratio <= 5:
            delta = usage_ratio - 4
            priority += 3500 * delta**2.5 + 300 * (1 - delta**1.5)
            for q in range(1, 10):
                priority += np.sin(usage_ratio * np.pi * q**1.3) * 30 / q
            if capacity % 4 < 1.5:
                priority += 60 * np.tan(capacity / 12)
            if usage_ratio < 4.6:
                priority -= 100 * np.exp(-7 * (usage_ratio - 4)**2)
        elif 3 < usage_ratio <= 4:
            priority += 2000 * (usage_ratio - 3)**3
            for r in range(1, 13):
                power = usage_ratio ** r
                if power < 0.7:
                    priority += power * 40 / r
                    if r % 4 == 1:
                        priority += 10 * r
                else:
                    priority += (1 - power / 1.5) * 25 / (r + 3)
                    if r == 6 and usage_ratio > 3.5:
                        priority += 35
            if capacity % 3.7 < 0.9:
                priority += 50 * np.sin(capacity * 4)
        elif 2 < usage_ratio <= 3:
            priority += 1800 * (usage_ratio - 2) ** 2.2
            for x in range(1, 15):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 5) - 0.6) * 18 / x
                if usage_ratio < 0.08 * x:
                    priority -= 15 * x
            if capacity < 0.07:
                priority += np.sqrt(capacity) * 520
            elif capacity < 1.3:
                priority += np.log1p(capacity * 35) * 65
            else:
                priority += (capacity % 9) * 40
        elif 1 < usage_ratio <= 2:
            priority += 1500 * (usage_ratio - 1) ** 1.9
            for y in range(1, 20):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 7) - 0.3) * 20 / y
                if usage_ratio < 0.1 * y:
                    priority -= 18 * y
            if capacity < 0.04:
                priority += np.cbrt(capacity) * 470
            elif capacity < 2:
                priority += np.log1p(capacity * 40) * 70
            else:
                priority += (capacity % 10) * 45
        elif 0.5 < usage_ratio <= 1:
            priority += 200 * (1 - usage_ratio)**2 + 130 * np.sqrt(usage_ratio)
            for z in range(1, 18):
                ratio_pow = usage_ratio ** z
                priority += (np.cos(ratio_pow * np.pi / 8) - 0.5) * 15 / z
                if usage_ratio < 0.06 * z:
                    priority -= 20 * z
            if capacity < 0.02:
                priority += np.sqrt(capacity) * 520
            elif capacity < 1.5:
                priority += np.log1p(capacity * 45) * 75
            else:
                priority += (capacity % 11) * 50
        else:
            priority += 300 * (1 - usage_ratio)**4
            for w in range(1, 25):
                ratio_pow = usage_ratio ** w
                priority += (np.sin(ratio_pow * np.pi / 9) - 0.6) * 12 / w
                if usage_ratio < 0.02 * w:
                    priority -= 22 * w
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 600
            elif capacity < 1.8:
                priority += np.log1p(capacity * 50) * 80
            else:
                priority += (capacity % 12) * 55
        if capacity < 0.03:
            priority += 100
            if usage_ratio > 0.85:
                priority += 120
            elif usage_ratio < 0.15:
                priority -= 70
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 25)
        elif capacity < 1.5:
            priority += 75
            if usage_ratio > 0.9:
                priority += 90
            elif usage_ratio < 0.35:
                priority -= 50
            for s in range(1, 7):
                if int(capacity * 1300) % (s + 6) == 0:
                    priority += s * 10
                else:
                    priority -= s * 4
        else:
            if usage_ratio < 0.18:
                priority -= 70
                for t in range(1, 8):
                    priority -= t * 6
            elif usage_ratio > 0.95:
                priority += 130
                for u in range(1, 6):
                    priority += u * 15
            else:
                priority += 45
        proximity_score = 0
        if int(capacity * 3500) % 29 == 0:
            proximity_score += 18
        if int(capacity * 950) % 31 == 0:
            proximity_score -= 14
        if int(capacity * 250) % 13 == 0:
            proximity_score += 17
        for k in range(1, 11):
            diff = abs(usage_ratio - k / 11)
            if diff < 0.02:
                proximity_score += 25 / k
            elif diff < 0.05:
                proximity_score += 12 / k
            else:
                proximity_score -= 6 / k
        for m in range(1, 9):
            mod_check = int(capacity * 2100) % (m + 11)
            if mod_check == 0:
                proximity_score += m * 7
            elif mod_check == 4:
                proximity_score -= m * 6
        for n in range(1, 6):
            mod_check = int(usage_ratio * 2000) % (n + 8)
            if mod_check == 0:
                proximity_score += 15 * n
            elif mod_check == 4:
                proximity_score -= 12 * n
        priority += proximity_score
        if usage_ratio < 0.005:
            for s in range(1, 10):
                priority -= s * 12
                if s % 3 == 0:
                    priority += 7 * s
        elif usage_ratio > 0.995:
            for t in range(1, 8):
                priority += t * 14
                if t == 4:
                    priority -= 20
        if capacity > 3:
            if capacity % 1 < 0.03:
                priority += 70
            if (int(capacity * 3500) % 29 == 0) and (usage_ratio > 0.7):
                priority += 80
            for v in range(1, 8):
                if (int(capacity * 900) % (v + 12) == 3) and (usage_ratio < 0.9):
                    priority -= 35
                elif (int(capacity * 900) % (v + 12) == 7) and (usage_ratio > 0.5):
                    priority += 45
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.5e4
        if abs(priority) > 2.2e4:
            priority = np.sign(priority) * 2.2e4
        priorities[i] = priority
    return priorities
